 {"id": "franken_networkx-copyedgeordfix", "title": "REVIEW: [MEDIUM] Graph copy reverses edge order", "description": "fnx copy methods iterated edge_py_attrs HashMap, producing non-deterministic edge order and occasional endpoint reversal. Fixed by iterating inner.edges_ordered.", "status": "closed", "priority": 3, "issue_type": "bug", "created_at": "2026-04-24T11:44:05.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:44:05.000000000Z", "closed_at": "2026-04-24T11:44:05.000000000Z", "close_reason": "Iterate edges_ordered", "source_repo": ".", "compaction_level": 0, "original_size": 0}
 {"id": "franken_networkx-graphtodigraph", "title": "REVIEW: [HIGH] DiGraph constructor drops reverse edges on undirected source", "description": "fnx.DiGraph(undirected_graph) returned only forward edges. Python _copy_constructor_graph_source used source.edges which yields only forward for undirected. Broke second_order_centrality on weighted paths with Singular matrix LinAlgError. Fixed by expanding undirected to directed when target is directed.", "status": "closed", "priority": 2, "issue_type": "bug", "created_at": "2026-04-24T11:44:05.000000000Z", "created_by": "cc-networkx", "updated_at": "2026-04-24T11:44:05.000000000Z", "closed_at": "2026-04-24T11:44:05.000000000Z", "close_reason": "expand_undirected_to_directed branch", "source_repo": ".", "compaction_level": 0, "original_size": 0}
